    46       * This is the server socket id for server side, connection id for client side.
    47       * @return socket id
    48       */
    49      String socketId();
    50
    51      /**
    52       * Child socket id.
    53       * This is the connection socket id for server side. For client side, this may be additional
    54       * identification of a request (pipeline id, stream id).
    55       * @return child socket id, never null
    56       */
    57      String childSocketId();
    58
    59      /**
    60       * Log a message with the current {@link #socketId()} and {@link #childSocketId()} to have
    61       * consistent logs mappable to sockets.
    62       *
    63       * @param logger logger to use
    64       * @param level log level to use
    65       * @param format format (can use string format pattern for the variables provided)
    66       * @param variables variables of the format
    67       */
    68      default void log(System.Logger logger,
    69                       System.Logger.Level level,
    70                       String format,
    71                       Object... variables) {
    72          if (logger.isLoggable(level)) {
    73              logger.log(level, message(format, variables));
    74          }
    75      }
    76
    77      /**
    78       * Log a message with the current {@link #socketId()} and {@link #childSocketId()} to have
    79       * consistent logs mappable to sockets.
    80       *
    81       * @param logger logger to use
    82       * @param level log level to use
